import {
	createContext,
	createEffect,
	createResource,
	createSignal,
	type JSX,
	useContext,
} from 'solid-js';
import { BackgroundApi, type ResponseError, UsersApi } from '@/api';
import type * as Models from '@/api/models';
import { useAuth } from '@/contexts/AuthContext';

interface BackgroundContextValue {
	currentBackground: () => string | undefined;
	setUserBackground: (backgroundUrl: string) => Promise<void>;
	isLoading: () => boolean;
	error: () => string | null;
	refreshBackground: () => Promise<void>;
	backgroundChoices: () => Models.BackgroundData[] | undefined;
	isLoadingChoices: () => boolean;
}

interface BackgroundProviderProps {
	children: JSX.Element;
}

const BackgroundContext = createContext<BackgroundContextValue>();

export const BackgroundProvider = (props: BackgroundProviderProps) => {
	const auth = useAuth();
	const [userBackground, setUserBackground] = createSignal<string>('');
	const [error, setError] = createSignal<string | null>(null);

	// Load default background once
	const [defaultBackground] = createResource(async () => {
		try {
			const api = new BackgroundApi();
			const response = await api.getDefaultBackground();
			if (response.success && response.data) {
				return response.data;
			}
			throw new Error(
				'Failed to fetch default background: ' + response.message,
			);
		} catch (err) {
			console.error('Error loading default background:', err);
			throw err;
		}
	});

	// Load background choices once
	const [backgroundChoices] = createResource(async () => {
		try {
			const backgroundApi = new BackgroundApi();
			const userApi = new UsersApi();

			// Fetch global background choices
			const globalResponse = await backgroundApi.getBackgroundChoices();
			let globalChoices: Models.BackgroundData[] = [];

			try {
				if (globalResponse.success && globalResponse.data) {
					globalChoices = globalResponse.data;
				} else {
					throw new Error(
						'Failed to fetch global background choices: ' +
							globalResponse.message,
					);
				}
			} catch (err) {
				if ((err as ResponseError).response?.status === 401) {
					auth.logout();
					return [];
				}
				throw err;
			}

			// Fetch user-specific background choices if authenticated
			let userChoices: Models.BackgroundData[] = [];
			if (auth.token()) {
				try {
					const userResponse = await userApi.getUserBackgroundChoices({
						authorization: `Bearer ${auth.token()}`,
					});
					if (userResponse.success && userResponse.data) {
						userChoices = userResponse.data;
					} else {
						throw new Error(
							'Failed to fetch user-specific background choices: ' +
								userResponse.message,
						);
					}
				} catch (err) {
					if ((err as ResponseError).response?.status === 401) {
						auth.logout();
						return [];
					}
					throw err;
				}
			}

			// Combine both global and user-specific choices, removing duplicates
			const allChoices = [...globalChoices, ...userChoices];
			return [...new Set(allChoices)];
		} catch (err) {
			console.error('Error loading background choices:', err);
			return [];
		}
	});

	// Auto-fetch user background on auth change
	createEffect(async () => {
		if (auth.isAuthenticated() && auth.token()) {
			await loadUserBackground();
		} else {
			setUserBackground('');
			setError(null);
		}
	});

	const loadUserBackground = async () => {
		if (!auth.token()) return;
		if (!auth.user()) {
			auth.logout();
			return;
		}

		try {
			const userApi = new UsersApi();
			const response = await userApi.getUserBackground({
				authorization: `Bearer ${auth.token()}`,
				background: auth.user()?.background ?? '',
			});
			if (response.success && response.data) {
				setUserBackground(response.data);
				setError(null);
			}
		} catch (err: any) {
			console.warn('Failed to load user background:', err);
			// Don't set error for missing user background - this is expected for new users
			// but it should always default to the default background.
			if ((err as ResponseError).response?.status !== 404) {
				setError(err.message);
			}
			if ((err as ResponseError).response?.status === 401) {
				auth.logout();
			}
		}
	};

	const updateUserBackground = async (backgroundUrl: string) => {
		if (!auth.token()) {
			throw new Error('Authentication required to update background');
		}

		try {
			const userApi = new UsersApi();
			const result = await userApi.setUserBackground({
				authorization: `Bearer ${auth.token()}`,
				background: backgroundUrl,
			});

			if (result.success) {
				setUserBackground(backgroundUrl);
				setError(null);

				// Update the user object in AuthContext with the new background
				const currentUser = auth.user();
				if (currentUser && auth.token()) {
					auth.update(
						{
							...currentUser,
							background: backgroundUrl,
						},
						auth.token()!,
					);
				}
			} else {
				throw new Error(result.message || 'Failed to update background');
			}
		} catch (err: any) {
			setError(err.message);
			if ((err as ResponseError).response?.status === 401) {
				auth.logout();
			}
			throw err;
		}
	};

	const refreshBackground = async () => {
		await loadUserBackground();
	};

	const contextValue: BackgroundContextValue = {
		currentBackground: () => userBackground() || defaultBackground(),
		setUserBackground: updateUserBackground,
		isLoading: () => defaultBackground.loading,
		error,
		refreshBackground,
		backgroundChoices,
		isLoadingChoices: () => backgroundChoices.loading,
	};

	return (
		<BackgroundContext.Provider value={contextValue}>
			{props.children}
		</BackgroundContext.Provider>
	);
};

export const useBackground = () => {
	const context = useContext(BackgroundContext);
	if (!context) {
		throw new Error('useBackground must be used within BackgroundProvider');
	}
	return context;
};
